#include <iostream>
#include <string>
#include <sstream>
#include <streambuf>

// This driver redirects stdin and captures stdout for testing.
std::string run_program_with_input(const std::string& input) {
    std::stringstream ss_in(input);
    std::stringstream ss_out;

    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    std::cin.rdbuf(ss_in.rdbuf());
    std::cout.rdbuf(ss_out.rdbuf());

    extern int main(); // Declare main to be callable
    main(); // Call the program's main function

    std::cin.rdbuf(old_cin_buf); // Restore original cin
    std::cout.rdbuf(old_cout_buf); // Restore original cout

    return ss_out.str();
}
